// Changed from KanbanCard to KanbanCardType
  let draggedCard = $state<KanbanCardType | null>(null);
  let sourceColumnId = $state<string | number | null>(null);
  let dragOverColumnId = $state<string | number | null>(null);

  const styles = kanbanBoard();

  // Changed parameter type from KanbanCard to KanbanCardType
  function handleDragStart(card: KanbanCardType, colId: string | number) {
    draggedCard = card;
    sourceColumnId = colId;
  }

  function handleDragOver(e: DragEvent, colId: string | number) {
    e.preventDefault();
    dragOverColumnId = colId;
  }

  function handleDragLeave(e: DragEvent) {
    const currentTarget = e.currentTarget as HTMLElement;
    const relatedTarget = e.relatedTarget as Node | null;
    if (!relatedTarget || !currentTarget.contains(relatedTarget)) {
      dragOverColumnId = null;
    }
  }

  function handleDrop(e: DragEvent, targetColId: string | number) {
    e.preventDefault();
    dragOverColumnId = null;

    if (draggedCard === null || sourceColumnId === null) return;
    if (sourceColumnId === targetColId) {
      draggedCard = null;
      sourceColumnId = null;
      return;
    }

    const fromCol = columns.find((c) => c.id === sourceColumnId);
    const toCol = columns.find((c) => c.id === targetColId);
    if (!fromCol || !toCol) return;

    fromCol.cards = fromCol.cards.filter((c) => c.id !== draggedCard!.id);
    toCol.cards = [...toCol.cards, draggedCard!];

    onMove(draggedCard, fromCol, toCol);

    draggedCard = null;
    sourceColumnId = null;
  }

  function handleDragEnd() {
    draggedCard = null;
    sourceColumnId = null;
    dragOverColumnId = null;
  }

export function warnThemeDeprecation(component: string, names: Record<string, unknown>, replacements?: Record<string, unknown>): void {
  if (!DEV) return;

  const nonEmptyNames = Object.keys(names).filter((name) => names[name]);
  if (nonEmptyNames.length === 0) return;

  let migrationHint = "";
  const usesClass = nonEmptyNames.some((name) => replacements?.[name] === "class");
  const propText = usesClass ? `"classes" or "class"` : `"classes"`;

  if (replacements) {
    const classProps: string[] = [];
    const classesObjectEntries: string[] = [];

    for (const name of nonEmptyNames) {
      const newKey = replacements[name];
      const value = names[name];
      if (!newKey || !value) continue;

      if (newKey === "class") {
        classProps.push(`class="${value}"`);
      } else {
        classesObjectEntries.push(`${newKey}: "${value}"`);
      }
    }

    const hintLines: string[] = [];
    if (classProps.length > 0) hintLines.push(...classProps);
    if (classesObjectEntries.length > 0) {
      hintLines.push(`classes={{ ${classesObjectEntries.join(", ")} }}`);
    }

    if (hintLines.length > 0) {
      migrationHint = `\nMigration example: ${hintLines.join(" ")}`;
    }
  }

  // Stack trace parsing to find external caller
  const stack = new Error().stack;
  const externalCaller = getExternalCaller(stack);

  console.warn(
    `⚠️ The following "${component}" props are deprecated: ${nonEmptyNames.map((n) => `"${n}"`).join(", ")}.\n` +
      `💡 Please use the ${propText} prop instead.${migrationHint}\n` +
      (externalCaller ? `🔍 Used at: ${externalCaller}` : "")
  );
}

import fs from "node:fs";
import path from "node:path";
import GithubSlugger from "github-slugger";
import { COMPONENTS_PATH } from "./constants";

const slugger = new GithubSlugger();

const SEARCH_INDEX_PATH = "./src/SEARCH_INDEX.json";
const H2_DELMIMITER = "## ";

type SearchDocument = {
  id: string;
  text: string;
  description: string;
  href: string;
  isComponent: boolean;
};

const files = fs.readdirSync(COMPONENTS_PATH);
const documents: SearchDocument[] = [];

for (const file of files) {
  slugger.reset();
  const [componentName] = file.split(".");
  if (!componentName) continue;
  const filePath = path.join(COMPONENTS_PATH, file);
  const fileContent = fs.readFileSync(filePath, "utf8");
  const lines = fileContent.split("\n");

  documents.push({
    id: `${componentName}-page`,
    text: componentName,
    description: componentName,
    href: `/components/${componentName}`,
    isComponent: true,
  });

  for (const line of lines) {
    if (line.startsWith(H2_DELMIMITER)) {
      const [, h2] = line.split(H2_DELMIMITER);
      if (!h2) continue;
      const hash = slugger.slug(h2);

      documents.push({
        id: componentName + hash,
        text: componentName,
        description: h2,
        href: `/components/${componentName}#${hash}`,
        isComponent: false,
      });
    }
  }
}

fs.writeFileSync(SEARCH_INDEX_PATH, JSON.stringify(documents, null, 2));

export const newConfigSchema = baseConfigSchema.extend({
	aliases: baseConfigSchema.shape.aliases.extend({
		ui: aliasSchema("ui").default(DEFAULT_CONFIG.aliases.ui),
		hooks: aliasSchema("hooks").default(DEFAULT_CONFIG.aliases.hooks),
		lib: aliasSchema("lib").default(DEFAULT_CONFIG.aliases.lib),
	}),
	registry: z.string().default(DEFAULT_CONFIG.registry),
	// design system
	style: z.string().optional(),
	iconLibrary: z.enum(ICON_LIBRARIES).optional(),
	menuColor: z.enum(MENU_COLORS).optional(),
	menuAccent: z.enum(MENU_ACCENTS).optional(),
});

export type RawConfig = z.infer<typeof rawConfigSchema>;
// combines the old with the new
export const rawConfigSchema = z.object({
	...originalConfigSchema.shape,
	...newConfigSchema.shape,
	aliases: z.object({
		...originalConfigSchema.shape.aliases.shape,
		...newConfigSchema.shape.aliases.shape,
	}),
});

export type ResolvedConfig = z.infer<typeof resolvedConfigSchema>;
export const resolvedConfigSchema = rawConfigSchema.extend({
	sveltekit: z.boolean(),
	resolvedPaths: z.object({
		cwd: z.string(),
		tailwindCss: z.string(),
		utils: z.string(),
		components: z.string(),
		hooks: z.string(),
		ui: z.string(),
		lib: z.string(),
	}),
	style: z.string().default(DEFAULT_CONFIG.style),
	iconLibrary: z.enum(ICON_LIBRARIES).default(DEFAULT_CONFIG.iconLibrary),
	menuColor: z.enum(MENU_COLORS).default(DEFAULT_CONFIG.menuColor),
	menuAccent: z.enum(MENU_ACCENTS).default(DEFAULT_CONFIG.menuAccent),
});

import path from "node:path";
import autoprefixer from "autoprefixer";
import { Glob } from "bun";
import postcss from "postcss";
import { compileAsync } from "sass";

const PARTIAL_FILE_REGEX = /^_/;

const glob = new Glob("*.scss");
const scss = Array.from(glob.scanSync({ cwd: "css" }))
  .filter((file) => !PARTIAL_FILE_REGEX.test(file))
  .map((file) => path.parse(file));

console.time("[build-css]");
await Promise.all(
  scss.map(async ({ name, base }) => {
    const file = `css/${base}`;
    const outFile = `css/${name}.css`;

    console.log("[build-css]", file, "-->", outFile);

    const { css } = await compileAsync(file, {
      style: "compressed",
      sourceMap: false,
      loadPaths: ["node_modules"],
      quietDeps: true,
      silenceDeprecations: [
        "import",
        "global-builtin",
        "color-functions",
        "if-function",
      ],
    });

    const prefixed = await postcss([
      autoprefixer({
        overrideBrowserslist: ["last 1 version", "ie >= 11", "Firefox ESR"],
      }),
    ]).process(css, { from: undefined });

    await Bun.write(outFile, prefixed.css);
  }),
);

const cssTypes = scss
  .map(
    ({ name }) => `declare module "carbon-components-svelte/css/${name}.css";`,
  )
  .join("\n");

await Bun.write("css/css.d.ts", `${cssTypes}\n`);

console.timeEnd("[build-css]");
